protected void verifyNonDup(AnnotatedWithParams newOne, int typeIndex, boolean explicit) {
    final int mask = (1 << typeIndex);
    _hasNonDefaultCreator = true;
    AnnotatedWithParams oldOne = _creators[typeIndex];
    if (oldOne != null) {
        if ((_explicitCreators & mask) != 0) {
            // Existing explicitly annotated, skip if new not annotated
            if (!explicit) {
                return;
            }
            // Conflict if both are explicit
            if (explicit) {
                throw new IllegalArgumentException("Conflicting "+TYPE_DESCS[typeIndex]
                        +" creators: already had explicitly marked "+oldOne+", encountered "+newOne);
            }
        } else {
            // Allow overrides if they are more specific
            if (!isMoreSpecific(oldOne, newOne)) {
                return;
            }
        }
    }
    // If explicit, mark it
    if (explicit) {
        _explicitCreators |= mask;
    }
    _creators[typeIndex] = _fixAccess(newOne);
}

private boolean isMoreSpecific(AnnotatedWithParams oldOne, AnnotatedWithParams newOne) {
    // A simple method to determine if newOne is more specific than oldOne
    return oldOne.getDeclaringClass().isAssignableFrom(newOne.getDeclaringClass());
}

protected void verifyNonDup(AnnotatedWithParams newOne, int typeIndex, boolean explicit) {
    final int mask = (1 << typeIndex);
    _hasNonDefaultCreator = true;
    AnnotatedWithParams oldOne = _creators[typeIndex];
    if (oldOne != null) {
        boolean bothExplicit = ((_explicitCreators & mask) != 0) && explicit;
        boolean sameType = oldOne.getClass() == newOne.getClass();

        if (bothExplicit && sameType) {
            throw new IllegalArgumentException("Conflicting " + TYPE_DESCS[typeIndex]
                    + " creators: already had explicitly marked " + oldOne + ", encountered " + newOne);
        }
    }
    if (explicit) {
        _explicitCreators |= mask;
    }
    _creators[typeIndex] = _fixAccess(newOne);
}

protected void verifyNonDup(AnnotatedWithParams newOne, int typeIndex, boolean explicit) {
    final int mask = (1 << typeIndex);
    _hasNonDefaultCreator = true;
    AnnotatedWithParams oldOne = _creators[typeIndex];

    if (oldOne != null) {
        boolean oldIsExplicit = ((_explicitCreators & mask) != 0);
        // Case 1: If both creators are explicit
        if (explicit && oldIsExplicit) {
            if (oldOne.getClass() == newOne.getClass()) {
                throw new IllegalArgumentException("Conflicting " + TYPE_DESCS[typeIndex]
                        + " creators: already had explicitly marked " + oldOne + ", encountered " + newOne);
            }
        }
        // Case 2: Allow explicit to override non-explicit
        else if (explicit && !oldIsExplicit) {
            _explicitCreators |= mask;
            _creators[typeIndex] = _fixAccess(newOne);
            return; // Early return after processing to avoid unnecessary operations
        }
        // Case 3: Handle same class without explicit conflict (selection based on specificity can be added here)
        else if (oldOne.getClass() == newOne.getClass()) {
            return; // Skip since classes are same and explicitness is handled
        }
    }
    // In case of no conflict or explicit taking precedence
    if (explicit) {
        _explicitCreators |= mask;
    }
    _creators[typeIndex] = _fixAccess(newOne);
}
